def gen(rng, size):
    n = max(1, min(size, 100))
    words = []
    for i in range(n):
        length = rng.randint(1, 100)
        if rng.random() < 0.15:
            half = [chr(rng.randint(97, 122)) for _ in range(length // 2)]
            mid = [chr(rng.randint(97, 122))] if length % 2 else []
            word = ''.join(half + mid + half[::-1])
        else:
            word = ''.join(chr(rng.randint(97, 122)) for _ in range(length))
        words.append(word)
    return [words]

