class Solution:
    def firstPalindrome(self, words):
        def is_pal(s):
            i, j = 0, len(s) - 1
            while i < j:
                if s[i] != s[j]:
                    return False
                i += 1
                j -= 1
            return True

        for w in words:
            if is_pal(w):
                return w
        return ''

